  price?: string;                // "14,400원" 등 (선택)
  priceNote?: string;            // "★ 쿠팡 로켓배송" 등 (선택)
  url: string;                   // 파트너스 추적 링크
  personaComment: string;        // 페르소나의 추천 한마디
